class Solution {public:
bool coinChange(vector<int>& coins, int amount) {
vector<int> dp(amount + 1, INT_MAX);
 dp[0] = 0;
for (int i = 1; i <= amount; i++)
    for (int coin : coins)
        if (i - coin >= 0)
            dp[i] = min(dp[i], dp[i - coin] + 1);
return dp[amount] != INT_MAX ? true : false;
}}
